module RefModule(CLK, EN, RST, COUNT);
input CLK, EN, RST;
output reg [3:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge CLK or posedge RST or posedge dbg_halt) begin
    if(RST)
        COUNT <= 4'b0000;
    else if(EN)
        COUNT <= COUNT + 1;
end

endmodule
